local function F()task.spawn(function()local F=0 local L={}local H=0 while task.wait(.1)do if not _G.Config or not _G.Config.AutoShake then continue end local k=game.Players.LocalPlayer local y=k:FindFirstChild("PlayerGui")if not y then continue end local f=y:FindFirstChild("shakeui")if not f then continue end if f:IsA("ScreenGui")and f.Enabled then f.Enabled=false end local q=f:FindFirstChild("safezone")if not q then continue end if q.Visible then q.Visible=false end H=H+.1 local m=q:GetChildren()if H>=.5 or#m~=F then H=0 F=#m L={}for F,H in pairs(m)do if H:IsA("ImageButton")or H:IsA("TextButton")then table.insert(L,H)end end end for F,L in pairs(L)do if L.Visible then pcall(function()if getconnections then for F,L in pairs(getconnections(L.MouseButton1Click))do L:Fire()end for F,L in pairs(getconnections(L.Activated))do L:Fire()end elseif firesignal then firesignal(L.MouseButton1Click)firesignal(L.Activated)end end)end end end end)end local function L(L)task.spawn(function()_G.Config.AutoShake=L if _G.Config.AutoShake then F()end end)end return L